import pymysql
import os
import json
from flask import Request

def search_database(request: Request):
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydb')
    db_host = os.environ.get('DB_HOST', 'localhost')
    
    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor
        )
        
        request_json = request.get_json(silent=True)
        request_args = request.args
        
        params = {}
        if request_json:
            params = request_json
        elif request_args:
            params = request_args.to_dict()
        
        table = params.get('table', 'users')
        
        base_query = f"SELECT * FROM {table}"
        
        conditions = []
        
        if 'name' in params:
            conditions.append(f"name = '{params['name']}'")
        
        if 'email' in params:
            conditions.append(f"email = '{params['email']}'")
        
        if 'status' in params:
            conditions.append(f"status = '{params['status']}'")
        
        if 'age' in params:
            conditions.append(f"age = {params['age']}")
        
        if 'min_age' in params:
            conditions.append(f"age >= {params['min_age']}")
        
        if 'max_age' in params:
            conditions.append(f"age <= {params['max_age']}")
        
        if 'city' in params:
            conditions.append(f"city = '{params['city']}'")
        
        if 'country' in params:
            conditions.append(f"country = '{params['country']}'")
        
        if 'search' in params:
            search_term = params['search']
            conditions.append(f"(name LIKE '%{search_term}%' OR email LIKE '%{search_term}%' OR city LIKE '%{search_term}%')")
        
        if 'id' in params:
            conditions.append(f"id = {params['id']}")
        
        if 'user_id' in params:
            conditions.append(f"user_id = {params['user_id']}")
        
        if 'category' in params:
            conditions.append(f"category = '{params['category']}'")
        
        if 'date_from' in params:
            conditions.append(f"created_at >= '{params['date_from']}'")
        
        if 'date_to' in params:
            conditions.append(f"created_at <= '{params['date_to']}'")
        
        if 'active' in params:
            conditions.append(f"active = {params['active']}")
        
        if 'role' in params:
            conditions.append(f"role = '{params['role']}'")
        
        if 'department' in params:
            conditions.append(f"department = '{params['department']}'")
        
        if 'price_min' in params:
            conditions.append(f"price >= {params['price_min']}")
        
        if 'price_max' in params:
            conditions.append(f"price <= {params['price_max']}")
        
        if 'custom_field' in params:
            conditions.append(f"{params['custom_field']} = '{params['custom_value']}'")
        
        if 'where' in params:
            conditions.append(params['where'])
        
        if conditions:
            where_clause = " AND ".join(conditions)
            query = f"{base_query} WHERE {where_clause}"
        else:
            query = base_query
        
        if 'order_by' in params:
            order_by = params['order_by']
            order_direction = params.get('order_direction', 'ASC')
            query += f" ORDER BY {order_by} {order_direction}"
        
        if 'limit' in params:
            query += f" LIMIT {params['limit']}"
        
        if 'offset' in params:
            query += f" OFFSET {params['offset']}"
        
        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'success': True,
                'data': results,
                'count': len(results),
                'query': query
            }),
            'headers': {
                'Content-Type': 'application/json'
            }
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'success': False,
                'error': str(e)
            }),
            'headers': {
                'Content-Type': 'application/json'
            }
        }
    
    finally:
        if connection:
            connection.close()